from abc import ABC, abstractmethod

class Animal(ABC):
    def __init__(self, name: str, sound: str):
        self._name = name      # convention: protected
        self.__sound = sound   # name-mangled: _Animal__sound

    @property
    def name(self) -> str:
        return self._name

    @abstractmethod
    def speak(self) -> str:
        pass

    def __str__(self) -> str:
        return f"{self._name} the {self.__class__.__name__}"

    def __repr__(self) -> str:
        return f"{self.__class__.__name__}(name='{self._name}')"


class Dog(Animal):
    def __init__(self, name: str, breed: str):
        super().__init__(name, sound="Woof")
        self.breed = breed

    def speak(self) -> str:
        return f"{self._name}: {self._Animal__sound}!"

    def fetch(self, item: str) -> str:
        return f"{self._name} fetches the {item}"


class Cat(Animal):
    def __init__(self, name: str, indoor: bool = True):
        super().__init__(name, sound="Meow")
        self.indoor = indoor

    def speak(self) -> str:
        return f"{self._name}: {self._Animal__sound}!"


# Polymorphism — same interface, different behavior
def make_speak(animals: list[Animal]):
    for animal in animals:
        print(animal.speak())

dog = Dog("Rex", "German Shepherd")
cat = Cat("Whiskers")
make_speak([dog, cat])

# Property access
print(dog.name)       # Rex (getter)
# dog.name = "Fido"   # would raise AttributeError (no setter)
print(repr(dog))       # Dog(name='Rex')
print(dog.fetch("ball"))  # Rex fetches the ball
```

