import json
from pathlib import Path

# Context manager — auto-closes file
def write_json(filepath: str, data: dict):
    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2)
    # file is closed here, even if json.dump raised

def read_json(filepath: str) -> dict:
    with open(filepath, 'r', encoding='utf-8') as f:
        return json.load(f)

# Exception handling hierarchy
class AppError(Exception):
    """Base exception for our application."""
    pass

class ValidationError(AppError):
    def __init__(self, field: str, message: str):
        self.field = field
        self.message = message
        super().__init__(f"{field}: {message}")

class NotFoundError(AppError):
    def __init__(self, resource: str, id: int):
        super().__init__(f"{resource} #{id} not found")

# Using exceptions
def process_user(data: dict):
    try:
        if "name" not in data:
            raise ValidationError("name", "Name is required")
        if "age" not in data:
            raise ValidationError("age", "Age is required")
        if data["age"] < 0:
            raise ValidationError("age", "Age must be non-negative")
        result = {"processed": True, **data}
    except ValidationError as e:
        print(f"Validation failed: {e.field} — {e.message}")
        result = {"processed": False, "error": str(e)}
    else:
        print("Processing succeeded")
    finally:
        print("Processing complete (always runs)")
    return result

